CREATE DATABASE IF NOT EXISTS `goosd_admin`;
USE `goosd_admin`;
SET FOREIGN_KEY_CHECKS=0;
DROP TABLE IF EXISTS `account_records`;
CREATE TABLE `account_records` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `record_no` varchar(40) NOT NULL COMMENT '流水编号',
  `user_id` bigint unsigned NOT NULL COMMENT '用户ID',
  `record_type` varchar(32) NOT NULL COMMENT '流水类型',
  `direction` varchar(16) NOT NULL COMMENT '资金方向',
  `order_id` bigint unsigned DEFAULT NULL COMMENT '关联订单ID',
  `order_no` varchar(40) DEFAULT NULL COMMENT '关联订单编号',
  `related_record_id` bigint unsigned DEFAULT NULL COMMENT '关联原流水ID',
  `status` varchar(32) NOT NULL DEFAULT 'success' COMMENT '流水状态',
  `ordered_quantity` int unsigned DEFAULT NULL COMMENT '下单数量快照',
  `completed_quantity` int unsigned DEFAULT NULL COMMENT '完成数量快照',
  `refunded_quantity` int unsigned DEFAULT NULL COMMENT '退款数量快照',
  `original_unit_price` decimal(18,4) DEFAULT NULL COMMENT '原始单价',
  `original_total_amount` decimal(18,4) DEFAULT NULL COMMENT '原价总金额',
  `discount_rate` decimal(10,4) DEFAULT NULL COMMENT '折扣率',
  `discounted_unit_price` decimal(18,4) DEFAULT NULL COMMENT '折后单价',
  `discount_amount` decimal(18,4) DEFAULT NULL COMMENT '优惠金额',
  `payable_amount` decimal(18,4) DEFAULT NULL COMMENT '应付金额',
  `actual_paid_amount` decimal(18,4) DEFAULT NULL COMMENT '实际支付金额',
  `refund_amount` decimal(18,4) DEFAULT NULL COMMENT '退款金额',
  `net_amount` decimal(18,4) NOT NULL DEFAULT '0.0000' COMMENT '本次净变动金额',
  `before_available_amount` decimal(18,4) NOT NULL DEFAULT '0.0000' COMMENT '变更前可用余额',
  `after_available_amount` decimal(18,4) NOT NULL DEFAULT '0.0000' COMMENT '变更后可用余额',
  `reason_code` varchar(64) DEFAULT NULL COMMENT '原因编码',
  `reason_message` varchar(255) DEFAULT NULL COMMENT '原因说明',
  `remark` varchar(255) DEFAULT NULL COMMENT '备注',
  `calc_snapshot` json DEFAULT NULL COMMENT '计费或退款计算快照',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_account_records_record_no` (`record_no`),
  KEY `idx_account_records_user_created_at` (`user_id`,`created_at`),
  KEY `idx_account_records_order_id` (`order_id`),
  KEY `idx_account_records_record_type_status` (`record_type`,`status`),
  KEY `idx_account_records_related_record_id` (`related_record_id`)
) ENGINE=InnoDB AUTO_INCREMENT=1938 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='账户流水记录表';
