DROP TABLE IF EXISTS `orders`;
CREATE TABLE `orders` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `order_no` varchar(40) NOT NULL COMMENT '订单编号',
  `user_id` bigint unsigned NOT NULL COMMENT '用户ID',
  `batch_id` bigint unsigned NOT NULL DEFAULT '0' COMMENT '来源批次ID',
  `batch_item_id` bigint unsigned NOT NULL DEFAULT '0' COMMENT '来源批次明细ID',
  `note_id` varchar(64) DEFAULT NULL COMMENT '小红书笔记ID',
  `note_url` varchar(1024) DEFAULT NULL COMMENT '小红书笔记链接',
  `target_type` varchar(32) NOT NULL DEFAULT 'view' COMMENT '下单目标类型',
  `ordered_quantity` int unsigned NOT NULL DEFAULT '0' COMMENT '下单数量',
  `completed_quantity` int unsigned NOT NULL DEFAULT '0' COMMENT '已完成数量',
  `refunded_quantity` int unsigned NOT NULL DEFAULT '0' COMMENT '已退款数量',
  `refund_amount_total` decimal(18,4) NOT NULL DEFAULT '0.0000' COMMENT '累计退款金额',
  `repair_count` int unsigned NOT NULL DEFAULT '0' COMMENT '补单次数',
  `order_status` varchar(32) NOT NULL DEFAULT 'running' COMMENT '订单状态',
  `external_task_id` varchar(128) DEFAULT NULL COMMENT '外部任务ID',
  `external_status` varchar(64) DEFAULT NULL COMMENT '外部任务状态',
  `external_progress` decimal(10,4) DEFAULT NULL COMMENT '外部任务进度',
  `external_completed_quantity` int unsigned NOT NULL DEFAULT '0' COMMENT '外部返回完成数量',
  `external_last_synced_at` datetime DEFAULT NULL COMMENT '外部进度同步时间',
  `reason_code` varchar(64) DEFAULT NULL COMMENT '原因编码',
  `reason_message` varchar(255) DEFAULT NULL COMMENT '原因说明',
  `snapshot_current_read_count` int unsigned DEFAULT NULL COMMENT '下单时阅读数快照',
  `snapshot_verified_read_count` int unsigned DEFAULT NULL COMMENT '验收时阅读数快照',
  `last_dispatch_at` datetime DEFAULT NULL COMMENT '最近投递时间',
  `last_verified_at` datetime DEFAULT NULL COMMENT '最近验收时间',
  `refund_lock_status` varchar(32) NOT NULL DEFAULT 'unlocked' COMMENT '退款锁状态',
  `refund_locked_at` datetime DEFAULT NULL COMMENT '退款锁定时间',
  `refund_requested_at` datetime DEFAULT NULL COMMENT '申请退款时间',
  `stop_requested_at` datetime DEFAULT NULL COMMENT '请求停止时间',
  `stop_response_message` varchar(255) DEFAULT NULL COMMENT '停止任务响应说明',
  `refund_calc_after_at` datetime DEFAULT NULL COMMENT '退款计算时间点',
  `archived_at` datetime DEFAULT NULL COMMENT '归档时间',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_orders_order_no` (`order_no`),
  KEY `idx_orders_user_created_at` (`user_id`,`created_at`),
  KEY `idx_orders_status_updated_at` (`order_status`,`updated_at`),
  KEY `idx_orders_batch_id` (`batch_id`),
  KEY `idx_orders_batch_item_id` (`batch_item_id`),
  KEY `idx_orders_note_id` (`note_id`),
  KEY `idx_orders_external_task_id` (`external_task_id`),
  KEY `idx_orders_refund_lock_status` (`refund_lock_status`),
  KEY `idx_orders_refund_calc_after_at` (`refund_calc_after_at`)
) ENGINE=InnoDB AUTO_INCREMENT=2179 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='订单主表';
